import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, ProjectContext } from "../../base.ts";

/**
 * 🌉 Dr. Bridge — PhD in Integration Contracts & FFI (TypeScript)
 * Generated by Sovereign Forge.
 */
export class BridgePersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "bridge";
        this.name = "Bridge";
        this.emoji = "🌉";
        this.role = "PhD Integration Architect";
        this.phd_identity = "Integration Contracts & FFI (TypeScript)";
        this.stack = "Bun";
        this.healingPrompt = "";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "fetch\\s*\\([^)]*\\)\\s*\\.then\\([^)]*\\)\\s*\\.then\\([^)]*as\\s+any",
                    "issue": "Contrato Quebrado: Resposta de API tipada como \"any\" — sem verificação PhD.",
                    "severity": "high"
          },
          {
                    "regex": "axios\\.(?:get|post|put|delete)\\s*<\\s*any\\s*>",
                    "issue": "Contrato Vago: Chamada HTTP sem tipo de resposta definido PhD.",
                    "severity": "high"
          },
          {
                    "regex": "JSON\\.parse\\([^)]+\\)(?!\\s*as\\b)",
                    "issue": "Risco de Runtime: JSON.parse sem type assertion — resultado é \"any\" PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "\\.json\\(\\)(?!\\s*as\\b)",
                    "issue": "Contrato Implícito: .json() sem tipagem de resposta PhD.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Bridge operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Bridge, PhD em Integration Contracts & FFI (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
